draw( (0,-2)-- (0,10) ,Arrows);
draw( (5,0) -- (-10,0),Arrows);

label("$l$",(2,10), NE);
label("$x$", (5,0) , E);
label("$y$", (0,-2) , S);
filldraw( (-8,0) -- (0,8) -- (0,0) -- cycle, lightgray);
